import java.util.Objects;

/**
 * Session Service for generating secure session IDs.
 * Provides cryptographically secure random session identifiers
 * for user authentication and authorization.
 */
public class SessionService {

    // Character set for session ID: uppercase, lowercase, and digits (62 characters total)
    private static final String CHAR_SET = 
        "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";

    // SecureRandom for cryptographically secure random number generation
    // SecureRandom is preferred over Random for security-sensitive applications
    private static final SecureRandom SECURE_RANDOM = new SecureRandom();

    // Default session ID length if not specified
    private static final int DEFAULT_LENGTH = 32;

    // Minimum allowed session ID length
    private static final int MIN_LENGTH = 1;

    // Maximum allowed session ID length to prevent memory issues
    private static final int MAX_LENGTH = 256;

    /**
     * Generates a secure session ID of the specified length.
     * 
     * @param length the desired length of the session ID
     * @return a random session ID string consisting of uppercase letters, 
     *         lowercase letters, and digits
     * @throws IllegalArgumentException if length is out of valid range (1-256)
     * @throws SecurityException if secure random generation fails
     */
    public String generate(int length) {
        // Validate input length
        if (length < MIN_LENGTH || length > MAX_LENGTH) {
            throw new IllegalArgumentException(
                String.format("Session ID length must be between %d and %d, got: %d", 
                    MIN_LENGTH, MAX_LENGTH, length)
            );
        }

        try {
            // Create StringBuilder with initial capacity for efficiency
            StringBuilder sessionId = new StringBuilder(length);

            // Generate random characters from the character set
            for (int i = 0; i < length; i++) {
                int randomIndex = SECURE_RANDOM.nextInt(CHAR_SET.length());
                sessionId.append(CHAR_SET.charAt(randomIndex));
            }

            return sessionId.toString();

        } catch (Exception e) {
            // Handle any unexpected exceptions during generation
            // Wrap in SecurityException to indicate security-related failure
            throw new SecurityException("Failed to generate secure session ID", e);
        }
    }

    /**
     * Generates a session ID with default length (32 characters).
     * 
     * @return a random session ID string with default length
     */
    public String generate() {
        return generate(DEFAULT_LENGTH);
    }
}

